const event = $json || {};
const requestBody = event.body && typeof event.body === "object" ? event.body : event;
const payload = requestBody.payload && typeof requestBody.payload === "object"
  ? requestBody.payload
  : requestBody;

const eventName = String(requestBody.event || payload.event || event.event || "").toLowerCase();
const rawFrom = payload.from || payload.chatId || payload.phone || payload.sender || "";
const from = String(rawFrom || "").trim();
const fromMe = Boolean(payload.fromMe);
const source = String(payload.source || "").toLowerCase();
// Para evitar mensagem duplicada, o piloto encaminha apenas o evento "message".
const isSupportedEvent = eventName === "message" || eventName === "";
const isDirectChat = !!from && !from.endsWith("@g.us") && !from.endsWith("@newsletter") && from !== "status@broadcast";
const shouldForward = isSupportedEvent && !fromMe && isDirectChat;

const media = payload.media && typeof payload.media === "object" ? payload.media : {};
const messageTypeRaw = String(payload.type || payload.message_type || media.mimetype || "").toLowerCase();
const mimeType = String(media.mimetype || payload.mimetype || "").toLowerCase();

let messageType = "text";
if (messageTypeRaw.includes("audio") || messageTypeRaw.includes("voice") || mimeType.startsWith("audio/") || payload.ptt === true) {
  messageType = "audio";
} else if (messageTypeRaw.includes("image") || messageTypeRaw.includes("photo") || mimeType.startsWith("image/")) {
  messageType = "image";
}

const textValue = payload.text?.body || payload.text || payload.body || payload.message || "";
const text = typeof textValue === "string" ? textValue.trim() : "";
const captionValue = media.caption || payload.caption || (messageType === "image" ? text : "");
const caption = typeof captionValue === "string" ? captionValue.trim() : "";
const mediaUrl = media.url || media.link || payload.media_url || payload.audio?.url || payload.audio?.link || payload.image?.url || payload.image?.link || "";
const externalMessageId = payload.id || payload.message_id || payload.external_message_id || requestBody.id || event.id || null;

return [{
  json: {
    should_forward: shouldForward,
    skip_reason: shouldForward ? undefined : `Evento ignorado: ${eventName || "desconhecido"}${fromMe ? " (fromMe)" : ""}${from ? "" : " (sem remetente)"}` ,
    phone: from || undefined,
    message_type: messageType,
    text: text || undefined,
    caption: caption || undefined,
    transcription_text: undefined,
    media_url: mediaUrl ? String(mediaUrl) : undefined,
    external_message_id: externalMessageId ? String(externalMessageId) : undefined,
    _meta: {
      event: eventName || undefined,
      from_me: fromMe,
      source: source || undefined
    },
    _raw_event: requestBody
  }
}];

const payload = { ...$json };

if (payload.message_type === "audio") {
  // Fluxo minimo para piloto: usa texto existente ou marcador, sem travar o pipeline
  payload.transcription_text = payload.transcription_text || payload.text || "Cliente enviou audio (sem transcricao no n8n).";
}

return [{ json: payload }];
